prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName (COUNT(DISTINCT ?msg) AS ?associatedMessageCount) WHERE {
  ?model a bboExt:Model .
  ?model tai:normalizedId "3d0f07f9b84c4e31bbca562f472c8885" .
  ?task tai:belongsTo ?choreo .
  ?task a bboExt:ChoreographyTask .
  ?choreo tai:belongsTo* ?model .

  OPTIONAL {
    ?assoc a bboExt:Association ;
           bbo:sourceRef ?srcStr ;
           bbo:targetRef ?tgtStr .
    FILTER(STR(?srcStr) = STR(?task) || CONTAINS(STR(?srcStr), REPLACE(STR(?task), ".*#", "")) || CONTAINS(STR(?srcStr), STRAFTER(STR(?task), "#")))
  }

  OPTIONAL {
    ?mf a bboExt:MessageFlow .
    ?mf bboExt:sourceRef ?src .
    ?mf bboExt:targetRef ?tgt .
  }

  # Count messages connected via message flows to the task (source or target)
  OPTIONAL {
    ?mf a bboExt:MessageFlow .
    ?mf tai:belongsTo ?choreo .
    FILTER(
      (CONTAINS(STR(?mf bboExt:sourceRef), "") )
    )
  }

  # Robust join: task id is referenced by messageflow source/target string IDs
  OPTIONAL {
    ?mf a bboExt:MessageFlow .
    ?mf tai:belongsTo ?choreo .
    FILTER(STRENDS(STR(?mf), "") )
  }
}
GROUP BY ?task ?taskName
HAVING (?associatedMessageCount = 2)
ORDER BY ?taskName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName (COUNT(DISTINCT ?msg) AS ?associatedMessageCount) WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "3d0f07f9b84c4e31bbca562f472c8885" .

  ?choreo tai:belongsTo ?model .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .
  OPTIONAL { ?task bbo:name ?taskName . }

  # Messages connected via message flows (source or target)
  ?mf a bboExt:MessageFlow ;
      tai:belongsTo ?choreo ;
      bboExt:sourceRef ?taskRefStr .
  FILTER(STR(?taskRefStr) = STRAFTER(STR(?task), "#") || STR(?taskRefStr) = STR(?task))

  OPTIONAL { ?mf bboExt:messageRef ?msg . }

  UNION

  ?mf2 a bboExt:MessageFlow ;
       tai:belongsTo ?choreo ;
       bboExt:targetRef ?taskRefStr2 .
  FILTER(STR(?taskRefStr2) = STRAFTER(STR(?task), "#") || STR(?taskRefStr2) = STR(?task))

  OPTIONAL { ?mf2 bboExt:messageRef ?msg . }
}
GROUP BY ?task ?taskName
HAVING (COUNT(DISTINCT ?msg) = 2)
ORDER BY ?taskName
LIMIT 25

