prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?mf ?srcRef ?tgtRef ?msgRef ?srcTaskName ?tgtTaskName WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "3d0f07f9b84c4e31bbca562f472c8885" .
  ?choreo tai:belongsTo ?model .

  ?mf a bboExt:MessageFlow ;
      tai:belongsTo ?choreo ;
      bboExt:sourceRef ?srcRef ;
      bboExt:targetRef ?tgtRef .
  OPTIONAL { ?mf bboExt:messageRef ?msgRef . }

  # try matching to task local part (common suffix)
  OPTIONAL {
    ?srcTask a bboExt:ChoreographyTask ;
             tai:belongsTo ?choreo ;
             bbo:id ?srcId .
    FILTER(STR(?srcId) = ?srcRef)
    OPTIONAL { ?srcTask bbo:name ?srcTaskName . }
  }
  OPTIONAL {
    ?tgtTask a bboExt:ChoreographyTask ;
             tai:belongsTo ?choreo ;
             bbo:id ?tgtId .
    FILTER(STR(?tgtId) = ?tgtRef)
    OPTIONAL { ?tgtTask bbo:name ?tgtTaskName . }
  }
}
ORDER BY ?mf
LIMIT 25

